    // To maximize the resulting number, we should place fragments that represent
    // a larger value (when placed at the beginning) earlier.
    // A fragment F1 comes before F2 if F1 + F2 > F2 + F1 (lexicographically for binary strings).
    // In binary representation, this comparison is equivalent to comparing how much
    // the leading '1's contribute.
    // For two fragments A and B:
    // A comes before B if A * 2^(len(B)) + B > B * 2^(len(A)) + A
    // This is equivalent to A * 2^(len(B)) - B * 2^(len(A)) > A - B.
    // A simpler, greedy approach that works for maximizing the number:
    // Compare the values represented by A and B, but consider their relative positions.
    // The standard trick for maximizing concatenated numbers (like in LeetCode 179) applies here.
    // We sort based on the comparison: (A + B) vs (B + A).

    const fragments = [];
    for (let i = 0; i < n; i++) {
        const num1 = nums1[i];
        const num0 = nums0[i];
        // Store the structure: [num1, num0]
        fragments.push({ num1: num1, num0: num0, index: i });
    }

    // Custom comparison function for sorting
    fragments.sort((fA, fB) => {
        // Construct the two potential concatenations: A + B and B + A
        // A = fA.num1 ones followed by fA.num0 zeros
        // B = fB.num1 ones followed by fB.num0 zeros

        // Helper to check if A + B > B + A
        // Since we are dealing with potentially large numbers, we simulate the string comparison.

        // A + B: [1^fA.num1][0^fA.num0] followed by [1^fB.num1][0^fB.num0]
        // B + A: [1^fB.num1][0^fB.num0] followed by [1^fA.num1][0^fA.num0]

        // We can compare these based on the first differing bit.

        // Let's analyze the structure: all 1s come first, then all 0s.
        // The decision boils down to which fragment starts with more '1's relative to its length,
        // or more accurately, which one pushes the subsequent 0s further right (more significant).

        // The standard comparison for maximizing concatenated numbers:
        // Compare string representation of (A + B) vs (B + A).

        // Function to generate the conceptual string for comparison
        const generateString = (f1, f2) => {
            let s = '1'.repeat(f1.num1) + '0'.repeat(f1.num0) + 
                    '1'.repeat(f2.num1) + '0'.repeat(f2.num0);
            return s;
        };

        const strAB = generateString(fA, fB);
        const strBA = generateString(fB, fA);

        // Standard lexicographical string comparison works for binary strings.
        if (strAB > strBA) {
            return -1; // fA should come before fB (return negative if A < B in sorting context, but here we want A before B if AB > BA)
        } else if (strAB < strBA) {
            return 1; // fB should come before fA
        } else {
            return 0;
        }
    });

