    let result = 0;

    for (const fragment of fragments) {
        const num1 = fragment.num1;
        const num0 = fragment.num0;
        const len = num1 + num0;

        // The fragment is: num1 ones followed by num0 zeros.
        // Value = (2^num1 - 1) * 2^num0 
        // Value = (2^num1) * 2^num0 - 2^num0
        // Value = 2^(num1 + num0) - 2^num0

        // We need to calculate this value contribution modulo MOD, and then add it 
        // to the current result, shifting the current result left by 'len'.

        // Contribution of the current fragment:
        // A sequence of 'num1' ones followed by 'num0' zeros contributes:
        // (2^num1 - 1) * 2^num0  (if we consider the fragment alone)

        // When appending to 'result' (which is already shifted by previous fragments' length),
        // the new value is: result * 2^len + FragmentValue.

        // Since we are calculating the final total value, we can calculate the contribution of the fragment
        // based on its position and add it to the running total.

        // Let L be the total length processed so far (sum of lengths of previous fragments).
        // The current fragment starts at position L (0-indexed from right, or 2^L position).
        // The value of the current fragment is: (2^num1 - 1) * 2^num0.
        // This value needs to be multiplied by 2^(Total Length - len).

        // A simpler way:
        // The current fragment contributes: (11...100...0)
        // 1. Contribution of '1's: num1 ones contribute 2^(len) - 2^num0 to the value if they were at the MSB.
        //    Each '1' at position k (0-indexed from right) contributes 2^k.
        //    The '1's occupy positions from len-1 down to len-num1.
        //    Contribution of 1s: Sum_{k=len-num1}^{len-1} 2^k = 2^(len) - 2^(len-num1)
        // 2. Contribution of '0's: 0.
        // Total value of fragment = 2^(len) - 2^(len - num1). Wait, this is wrong.

        // Correct value of the fragment F = 1...10...0 (num1 ones, num0 zeros):
        // F = (2^num1 - 1) * 2^num0.

        // We are appending this value to the right of the current 'result'.
        // New_Result = Old_Result * 2^len + FragmentValue

        // Modular Exponentiation helper
        const power = (base, exp) => {
            let res = 1;
            base %= MOD;
            while (exp > 0) {
                if (exp % 2 === 1) {
                    res = (res * base) % MOD;
                }
                base = (base * base) % MOD;
                exp = Math.floor(exp / 2);
            }
            return res;
        };

        // 1. Calculate FragmentValue = (2^num1 - 1) * 2^num0 mod MOD
        // Term 1: 2^num1 - 1
        let term1_pow = power(2, num1);
        let term1 = (term1_pow - 1 + MOD) % MOD;

        // Term 2: 2^num0
        let term2 = power(2, num0);

        // FragmentValue = Term1 * Term2
        let fragmentValue = (term1 * term2) % MOD;

        // 2. Update result: result = result * 2^len + fragmentValue

        // Shift result left by len: result * 2^len
        const shift = power(2, len);
        let newResult = (BigInt(result) * BigInt(shift) % BigInt(MOD)) + BigInt(fragmentValue);
        newResult %= BigInt(MOD);

        result = Number(newResult);
